// Normalize webhook input + verify internal auth
const input = $input.first().json;
const data = input.body || input;

const headers = input.headers || {};
const secret = headers['x-handler-secret'] || data._handler_secret || '';
const EXPECTED = $vars.GW_HANDLER_INTERNAL_SECRET;

if (secret !== EXPECTED && headers['x-handler-secret'] !== EXPECTED) {
  const isWebhook = !!input.headers;
  if (isWebhook) {
    return [{ json: { error: true, message: 'Unauthorized handler call', status_code: 403 } }];
  }
}

if (data._handler_secret) delete data._handler_secret;
return [{ json: data }];

// Handover Action Router — routes to action-specific logic
// Principle 1: Zero hardcoded values
// Principle 3: Config-driven via $vars
const input = $input.first().json;
const action = input.action;
const params = input.params || {};
const N8N_HOST = $vars.N8N_HOST;
const API_KEY = $vars.N8N_INTERNAL_API_KEY;
const SESSION_TABLE_ID = $vars.SESSION_STATE_TABLE_ID || '';

const GITHUB_RAW = 'https://raw.githubusercontent.com';
const GITHUB_OWNER = (input.config && input.config.metadata && input.config.metadata.github_owner) || params.github_owner || 'mishaal-cloud';
const GITHUB_REPO = (input.config && input.config.metadata && input.config.metadata.github_repo) || params.github_repo || 'n8n-ops';
const GITHUB_BRANCH = params.branch || 'main';

const AVAILABLE_ACTIONS = [
  'get_governing_spec', 'get_handover_template', 'run_preflight',
  'run_audit', 'get_session_state', 'update_session_state', 'get_skill_version',
  'get_platform_context',
  'safe_modify_workflow', 'log_change'
];

if (!action || !AVAILABLE_ACTIONS.includes(action)) {
  return [{json: {
    ok: false,
    error: { type: 'action_error', message: `Unknown handover action: ${action}. Available: ${AVAILABLE_ACTIONS.join(', ')}` },
    data: null
  }}];
}

try {
  // === get_governing_spec ===
  if (action === 'get_governing_spec') {
    const url = `${GITHUB_RAW}/${GITHUB_OWNER}/${GITHUB_REPO}/${GITHUB_BRANCH}/docs/governing-spec.md`;
    const resp = await this.helpers.httpRequest({ method: 'GET', url, returnFullResponse: true, ignoreHttpStatusErrors: true });
    if (resp.statusCode >= 400) {
      return [{json: { ok: false, error: { type: 'fetch_error', message: `Failed to fetch governing spec: HTTP ${resp.statusCode}` }, data: null }}];
    }
    return [{json: { ok: true, data: { content: resp.body, source: url }, error: null }}];
  }

  // === get_handover_template ===
  if (action === 'get_handover_template') {
    const url = `${GITHUB_RAW}/${GITHUB_OWNER}/${GITHUB_REPO}/${GITHUB_BRANCH}/docs/skills/n8n-handover-framework/templates/handover-doc-template.md`;
    const resp = await this.helpers.httpRequest({ method: 'GET', url, returnFullResponse: true, ignoreHttpStatusErrors: true });
    if (resp.statusCode >= 400) {
      return [{json: { ok: false, error: { type: 'fetch_error', message: `Failed to fetch handover template: HTTP ${resp.statusCode}` }, data: null }}];
    }
    return [{json: { ok: true, data: { content: resp.body, source: url }, error: null }}];
  }

  // === run_preflight ===
  if (action === 'run_preflight') {
    const checks = {};

    // 1. API connectivity
    try {
      const r = await this.helpers.httpRequest({ method: 'GET', url: `${N8N_HOST}/api/v1/workflows?limit=1`, headers: { 'X-N8N-API-KEY': API_KEY }, json: true });
      checks.api_connectivity = { status: 'PASS', detail: 'n8n API reachable' };
    } catch(e) {
      checks.api_connectivity = { status: 'FAIL', detail: e.message };
    }

    // 2. Workflow count
    try {
      const r = await this.helpers.httpRequest({ method: 'GET', url: `${N8N_HOST}/api/v1/workflows?limit=250`, headers: { 'X-N8N-API-KEY': API_KEY }, json: true });
      const count = (r.data || []).length;
      checks.workflow_count = { status: 'PASS', detail: `${count} workflows found` };
    } catch(e) {
      checks.workflow_count = { status: 'FAIL', detail: e.message };
    }

    // 3. Variables check
    try {
      const r = await this.helpers.httpRequest({ method: 'GET', url: `${N8N_HOST}/api/v1/variables?limit=250`, headers: { 'X-N8N-API-KEY': API_KEY }, json: true });
      const count = (r.data || r || []).length;
      checks.variable_count = { status: 'PASS', detail: `${count} variables found` };
    } catch(e) {
      checks.variable_count = { status: 'FAIL', detail: e.message };
    }

    // 4. Session-config webhook
    try {
      const r = await this.helpers.httpRequest({ method: 'POST', url: `${N8N_HOST}/webhook/session-config`, headers: { 'Content-Type': 'application/json' }, body: '{}', returnFullResponse: true, ignoreHttpStatusErrors: true });
      checks.session_config = { status: r.statusCode < 400 ? 'PASS' : 'FAIL', detail: `HTTP ${r.statusCode}` };
    } catch(e) {
      checks.session_config = { status: 'FAIL', detail: e.message };
    }

    // 5. Gateway v2 reachable
    try {
      const r = await this.helpers.httpRequest({ method: 'POST', url: `${N8N_HOST}/webhook/orchestrate-v2`, headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({domain:'test',action:'ping',client:'ascend'}), returnFullResponse: true, ignoreHttpStatusErrors: true });
      checks.gateway_v2 = { status: r.statusCode < 500 ? 'PASS' : 'FAIL', detail: `HTTP ${r.statusCode}` };
    } catch(e) {
      checks.gateway_v2 = { status: 'FAIL', detail: e.message };
    }

    const allPass = Object.values(checks).every(c => c.status === 'PASS');
    return [{json: { ok: true, data: { overall: allPass ? 'PASS' : 'PARTIAL', checks, timestamp: new Date().toISOString() }, error: null }}];
  }

  // === run_audit ===
  if (action === 'run_audit') {
    const workflowIds = params.workflow_ids || [];
    const auditAll = params.all === true;

    let workflows = [];
    if (auditAll) {
      const r = await this.helpers.httpRequest({ method: 'GET', url: `${N8N_HOST}/api/v1/workflows?limit=250`, headers: { 'X-N8N-API-KEY': API_KEY }, json: true });
      workflows = (r.data || []);
    } else if (workflowIds.length > 0) {
      for (const wfId of workflowIds) {
        try {
          const r = await this.helpers.httpRequest({ method: 'GET', url: `${N8N_HOST}/api/v1/workflows/${wfId}`, headers: { 'X-N8N-API-KEY': API_KEY }, json: true });
          workflows.push(r);
        } catch(e) {
          workflows.push({ id: wfId, name: 'FETCH_FAILED', nodes: [], _error: e.message });
        }
      }
    } else {
      return [{json: { ok: false, error: { type: 'param_error', message: 'run_audit requires workflow_ids array or all:true' }, data: null }}];
    }

    const violations = [];
    for (const wf of workflows) {
      if (wf._error) { violations.push({ workflow_id: wf.id, severity: 'error', rule: 'fetch_failed', message: wf._error }); continue; }
      for (const node of (wf.nodes || [])) {
        if (node.type !== 'n8n-nodes-base.code') continue;
        const code = (node.parameters && node.parameters.jsCode) || '';

        // Check for hardcoded URLs
        const hostMatches = code.match(/https?:\/\/[a-z0-9-]+\.app\.n8n\.cloud/gi) || [];
        for (const m of hostMatches) {
          violations.push({ workflow_id: wf.id, workflow_name: wf.name, node: node.name, severity: 'critical', rule: 'hardcoded_url', message: `Hardcoded URL: ${m}` });
        }

        // Check for hardcoded API keys (long alphanumeric strings that look like keys)
        if (/eyJ[A-Za-z0-9_-]{20,}/.test(code)) {
          violations.push({ workflow_id: wf.id, workflow_name: wf.name, node: node.name, severity: 'critical', rule: 'hardcoded_api_key', message: 'Possible hardcoded API key (JWT pattern)' });
        }

        // Check for hardcoded table IDs (without $vars reference)
        const tableIdPattern = /['"][a-zA-Z0-9]{16,}['"]/g;
        const tableMatches = code.match(tableIdPattern) || [];
        // Filter out common false positives (UUIDs in webhookId, known constants)
        for (const m of tableMatches) {
          const val = m.slice(1, -1);
          if (val.includes('-')) continue; // UUID format, likely webhookId
          if (code.includes('$vars') && code.includes(val)) continue; // Referenced via $vars
          violations.push({ workflow_id: wf.id, workflow_name: wf.name, node: node.name, severity: 'warning', rule: 'possible_hardcoded_id', message: `Possible hardcoded ID: ${val.substring(0,8)}...` });
        }
      }
    }

    return [{json: { ok: true, data: { workflows_scanned: workflows.length, violation_count: violations.length, violations, timestamp: new Date().toISOString() }, error: null }}];
  }

  // === get_session_state ===
  if (action === 'get_session_state') {
    if (!SESSION_TABLE_ID) {
      return [{json: { ok: false, error: { type: 'config_error', message: 'SESSION_STATE_TABLE_ID variable not set' }, data: null }}];
    }
    const sessionId = params.session_id;
    const url = `${N8N_HOST}/api/v1/data-tables/${SESSION_TABLE_ID}/rows?limit=250`;
    const r = await this.helpers.httpRequest({ method: 'GET', url, headers: { 'X-N8N-API-KEY': API_KEY }, json: true });
    const rows = r.data || [];

    if (sessionId) {
      const match = rows.filter(row => row.session_id === sessionId);
      const latest = match.length > 0 ? match[match.length - 1] : null;
      if (latest && latest.state) {
        try { latest._parsed_state = JSON.parse(latest.state); } catch(e) {}
      }
      return [{json: { ok: true, data: latest, error: null }}];
    }

    // Return latest session (highest ID)
    const latest = rows.length > 0 ? rows[rows.length - 1] : null;
    if (latest && latest.state) {
      try { latest._parsed_state = JSON.parse(latest.state); } catch(e) {}
    }
    return [{json: { ok: true, data: latest, error: null }}];
  }

  // === update_session_state ===
  if (action === 'update_session_state') {
    if (!SESSION_TABLE_ID) {
      return [{json: { ok: false, error: { type: 'config_error', message: 'SESSION_STATE_TABLE_ID variable not set' }, data: null }}];
    }
    const sessionId = params.session_id;
    const state = params.state;
    if (!sessionId || !state) {
      return [{json: { ok: false, error: { type: 'param_error', message: 'update_session_state requires session_id and state' }, data: null }}];
    }
    const stateStr = typeof state === 'string' ? state : JSON.stringify(state);
    const model = params.model || 'unknown';
    const url = `${N8N_HOST}/api/v1/data-tables/${SESSION_TABLE_ID}/rows`;
    const r = await this.helpers.httpRequest({
      method: 'POST', url, headers: { 'X-N8N-API-KEY': API_KEY, 'Content-Type': 'application/json' },
      body: JSON.stringify({ data: [{ session_id: sessionId, model, state: stateStr, updated_at: new Date().toISOString() }] })
    });
    return [{json: { ok: true, data: { session_id: sessionId, written: true, response: r }, error: null }}];
  }

  // === get_skill_version ===
  if (action === 'get_skill_version') {
    const versionUrl = `${GITHUB_RAW}/${GITHUB_OWNER}/${GITHUB_REPO}/${GITHUB_BRANCH}/docs/skills/n8n-handover-framework/VERSION`;
    let version = 'unknown';
    try {
      const r = await this.helpers.httpRequest({ method: 'GET', url: versionUrl, returnFullResponse: true, ignoreHttpStatusErrors: true });
      version = r.statusCode < 400 ? (r.body || '').trim() : 'not_found';
    } catch(e) { version = 'fetch_error'; }

    const skillUrl = `${GITHUB_RAW}/${GITHUB_OWNER}/${GITHUB_REPO}/${GITHUB_BRANCH}/docs/skills/n8n-handover-framework/SKILL.md`;
    let description = '';
    try {
      const r = await this.helpers.httpRequest({ method: 'GET', url: skillUrl, returnFullResponse: true, ignoreHttpStatusErrors: true });
      if (r.statusCode < 400) {
        const lines = (r.body || '').split('\n').slice(0, 10);
        description = lines.join('\n').substring(0, 500);
      }
    } catch(e) {}

    return [{json: { ok: true, data: { version, description, last_updated: new Date().toISOString(), source: versionUrl }, error: null }}];
  }

  // === get_platform_context ===
  // Single-call context for any AI session. Returns health, recent changes, gotchas, and verified state.
  // Every new session should call this FIRST before doing any work.
  if (action === 'get_platform_context') {
    const HEALTH_TABLE = $vars.CREDENTIAL_HEALTH_TABLE_ID || '';
    const CHANGELOG_TABLE = $vars.PLATFORM_CHANGELOG_TABLE_ID || '';

    // 1. Get credential health (latest per domain)
    let health = { healthy: [], degraded: [], down: [] };
    if (HEALTH_TABLE) {
      try {
        const hr = await this.helpers.httpRequest({ method: 'GET', url: `${N8N_HOST}/api/v1/data-tables/${HEALTH_TABLE}/rows?limit=250`, headers: { 'X-N8N-API-KEY': API_KEY }, json: true });
        const rows = hr.data || [];
        const latest = {};
        for (const row of rows) {
          const d = row.domain;
          if (!latest[d] || row.id > latest[d].id) latest[d] = row;
        }
        for (const [domain, row] of Object.entries(latest)) {
          if (row.status === 'healthy') health.healthy.push(domain);
          else if (row.status === 'degraded') health.degraded.push({ domain, error: row.error_message || '' });
          else health.down.push({ domain, error: row.error_message || '', error_type: row.error_type || '' });
        }
      } catch(e) { health.error = e.message; }
    }

    // 2. Get recent changelog (last 20 entries)
    let changelog = [];
    if (CHANGELOG_TABLE) {
      try {
        const cr = await this.helpers.httpRequest({ method: 'GET', url: `${N8N_HOST}/api/v1/data-tables/${CHANGELOG_TABLE}/rows?limit=20`, headers: { 'X-N8N-API-KEY': API_KEY }, json: true });
        changelog = (cr.data || []).reverse();
      } catch(e) {}
    }

    // 3. Get latest verified state from session_state
    let verifiedState = null;
    if (SESSION_TABLE_ID) {
      try {
        const sr = await this.helpers.httpRequest({ method: 'GET', url: `${N8N_HOST}/api/v1/data-tables/${SESSION_TABLE_ID}/rows?limit=250`, headers: { 'X-N8N-API-KEY': API_KEY }, json: true });
        const rows = (sr.data || []).filter(r => r.session_id && r.session_id.startsWith('verified-state'));
        const latest = rows.length > 0 ? rows[rows.length - 1] : null;
        if (latest && latest.state) {
          try { verifiedState = JSON.parse(latest.state); } catch(e) { verifiedState = latest.state; }
        }
      } catch(e) {}
    }

    return [{json: {
      ok: true,
      data: {
        health,
        recent_changes: changelog,
        verified_state: verifiedState,
        gotchas: verifiedState?.gotchas || [
          'Webhook re-registration required after API workflow updates (toggle OFF/ON)',
          'Registry client field must be all for shared services',
          'DataTable row DELETE not supported via n8n Cloud API',
          'Capabilities catalog may be stale - verify against handler code',
          'E2E health data lags behind reality - verify with live gateway calls'
        ],
        datatable_ids: verifiedState?.datatable_ids_verified || {},
        timestamp: new Date().toISOString()
      },
      error: null
    }}];
  }


  // === safe_modify_workflow ===
  // THE way to modify any workflow. Snapshots to GitHub first, applies change, logs to changelog, sends Slack alert.
  // Every AI session and tool MUST use this instead of raw PUT /workflows/{id}.
  if (action === 'safe_modify_workflow') {
    const wfId = params.workflow_id;
    const changes = params.changes; // {name, nodes, connections, settings}
    const reason = params.reason || 'No reason provided';
    const sessionId = params.session_id || 'unknown-session';

    if (!wfId) return [{json: {ok: false, error: {type: 'param_error', message: 'workflow_id is required'}, data: null}}];
    if (!changes) return [{json: {ok: false, error: {type: 'param_error', message: 'changes object is required (name, nodes, connections, settings)'}, data: null}}];

    // Step 1: GET current workflow state
    let currentWf;
    try {
      currentWf = await this.helpers.httpRequest({
        method: 'GET', url: N8N_HOST + '/api/v1/workflows/' + wfId,
        headers: {'X-N8N-API-KEY': API_KEY}, json: true
      });
    } catch(e) {
      return [{json: {ok: false, error: {type: 'fetch_error', message: 'Could not fetch workflow ' + wfId + ': ' + e.message}, data: null}}];
    }

    // Step 2: Snapshot to GitHub
    const timestamp = new Date().toISOString().replace(/[:.]/g, '-').slice(0, 19);
    const snapshotPath = 'snapshots/' + wfId + '/' + timestamp + '.json';
    const snapshotContent = JSON.stringify({
      snapshot_at: new Date().toISOString(),
      reason: 'Pre-modification snapshot: ' + reason,
      session_id: sessionId,
      workflow: {name: currentWf.name, id: currentWf.id, active: currentWf.active, nodes: currentWf.nodes, connections: currentWf.connections, settings: currentWf.settings}
    }, null, 2);

    try {
      await this.helpers.httpRequest({
        method: 'PUT',
        url: 'https://api.github.com/repos/' + GITHUB_OWNER + '/' + GITHUB_REPO + '/contents/' + snapshotPath,
        headers: {
          'Authorization': 'token ' + ($vars.GITHUB_PAT || ''),
          'Accept': 'application/vnd.github.v3+json',
          'Content-Type': 'application/json'
        },
        body: JSON.stringify({
          message: 'Snapshot ' + currentWf.name + ' before modification: ' + reason,
          content: Buffer.from(snapshotContent).toString('base64')
        })
      });
    } catch(e) {
      // Try via gateway GitHub handler as fallback
      try {
        const gwUrl = N8N_HOST + '/webhook/handler-github';
        await this.helpers.httpRequest({
          method: 'POST', url: gwUrl,
          headers: {'x-handler-secret': $vars.GW_HANDLER_INTERNAL_SECRET, 'Content-Type': 'application/json'},
          body: JSON.stringify({
            domain: 'github', action: 'create_or_update_file', client: 'ascend',
            params: {owner: GITHUB_OWNER, repo: GITHUB_REPO, path: snapshotPath, message: 'Snapshot ' + currentWf.name + ' before modification: ' + reason, content: snapshotContent}
          })
        });
      } catch(e2) {
        return [{json: {ok: false, error: {type: 'snapshot_error', message: 'Could not snapshot to GitHub: ' + e.message + ' / ' + e2.message}, data: null}}];
      }
    }

    // Step 3: Apply the modification
    const allowedSettings = {};
    const newSettings = changes.settings || currentWf.settings || {};
    for (const k of ['executionOrder', 'callerPolicy', 'errorWorkflow']) {
      if (newSettings[k]) allowedSettings[k] = newSettings[k];
    }

    let updatedWf;
    try {
      updatedWf = await this.helpers.httpRequest({
        method: 'PUT', url: N8N_HOST + '/api/v1/workflows/' + wfId,
        headers: {'X-N8N-API-KEY': API_KEY, 'Content-Type': 'application/json'},
        body: JSON.stringify({
          name: changes.name || currentWf.name,
          nodes: changes.nodes || currentWf.nodes,
          connections: changes.connections || currentWf.connections,
          settings: allowedSettings
        })
      });
    } catch(e) {
      return [{json: {ok: false, error: {type: 'update_error', message: 'PUT failed: ' + e.message + '. Snapshot saved at ' + snapshotPath}, data: null}}];
    }

    // Step 4: Re-register webhooks if needed
    const hasWebhook = (changes.nodes || currentWf.nodes).some(n => (n.type || '').includes('webhook'));
    if (hasWebhook && currentWf.active) {
      try {
        await this.helpers.httpRequest({method: 'POST', url: N8N_HOST + '/api/v1/workflows/' + wfId + '/deactivate', headers: {'X-N8N-API-KEY': API_KEY}});
        await new Promise(r => setTimeout(r, 1500));
        await this.helpers.httpRequest({method: 'POST', url: N8N_HOST + '/api/v1/workflows/' + wfId + '/activate', headers: {'X-N8N-API-KEY': API_KEY}});
      } catch(e) {} // Non-fatal
    }

    // Step 5: Log to changelog
    const CHANGELOG_TABLE = $vars.PLATFORM_CHANGELOG_TABLE_ID || '';
    if (CHANGELOG_TABLE) {
      try {
        await this.helpers.httpRequest({
          method: 'POST', url: N8N_HOST + '/api/v1/data-tables/' + CHANGELOG_TABLE + '/rows',
          headers: {'X-N8N-API-KEY': API_KEY, 'Content-Type': 'application/json'},
          body: JSON.stringify({data: [{
            timestamp: new Date().toISOString(),
            category: 'workflow_modification',
            domain: currentWf.name,
            summary: reason,
            details: 'Workflow ' + wfId + ' modified. Snapshot: ' + snapshotPath + '. Webhook re-registered: ' + hasWebhook,
            session_id: sessionId
          }]})
        });
      } catch(e) {} // Non-fatal
    }

    // Step 6: Slack notification
    try {
      const slackUrl = N8N_HOST + '/webhook/handler-google-suite';
      await this.helpers.httpRequest({
        method: 'POST', url: slackUrl,
        headers: {'x-handler-secret': $vars.GW_HANDLER_INTERNAL_SECRET, 'Content-Type': 'application/json'},
        body: JSON.stringify({
          domain: 'slack', action: 'post_message', client: 'ascend',
          params: {
            channel: '#n8n-alerts',
            text: ':wrench: *Workflow Modified*\n*' + currentWf.name + '* (' + wfId + ')\n*Reason:* ' + reason + '\n*Session:* ' + sessionId + '\n*Snapshot:* `' + snapshotPath + '`'
          }
        })
      });
    } catch(e) {} // Non-fatal

    return [{json: {
      ok: true,
      data: {
        workflow_id: wfId,
        workflow_name: updatedWf.name || currentWf.name,
        snapshot_path: snapshotPath,
        webhook_re_registered: hasWebhook,
        changelog_logged: !!CHANGELOG_TABLE,
        slack_notified: true
      },
      error: null
    }}];
  }

  // === log_change ===
  // Record any platform change (DataTable inserts, variable updates, config changes)
  if (action === 'log_change') {
    const CHANGELOG_TABLE = $vars.PLATFORM_CHANGELOG_TABLE_ID || '';
    if (!CHANGELOG_TABLE) return [{json: {ok: false, error: {type: 'config_error', message: 'PLATFORM_CHANGELOG_TABLE_ID not set'}, data: null}}];

    const entry = {
      timestamp: new Date().toISOString(),
      category: params.category || 'platform_change',
      domain: params.domain || 'unknown',
      summary: params.summary || 'No summary',
      details: params.details || '',
      session_id: params.session_id || 'unknown'
    };

    try {
      await this.helpers.httpRequest({
        method: 'POST', url: N8N_HOST + '/api/v1/data-tables/' + CHANGELOG_TABLE + '/rows',
        headers: {'X-N8N-API-KEY': API_KEY, 'Content-Type': 'application/json'},
        body: JSON.stringify({data: [entry]})
      });
      return [{json: {ok: true, data: {logged: true, entry}, error: null}}];
    } catch(e) {
      return [{json: {ok: false, error: {type: 'log_error', message: e.message}, data: null}}];
    }
  }


} catch (error) {
  return [{json: { ok: false, error: { type: 'system_error', message: error.message, stack: error.stack?.substring(0, 300) }, data: null }}];
}
